import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useStore } from '../context/store';
import { SKILLS } from '../data/skills';
import AIChat from '../components/AIChat';

export default function Dashboard() {
  const navigate = useNavigate();
  const { user, logout, enrolledSkills, getSkillProgress } = useStore();
  const [showChat, setShowChat] = useState(false);
  const enrolled = SKILLS.filter(s => enrolledSkills.includes(s.id));

  const handleLogout = () => { logout(); navigate('/'); };

  return (
    <div style={{ minHeight: '100vh', background: 'var(--bg)', display: 'flex' }}>
      {/* Sidebar */}
      <div style={{ width: 220, background: 'var(--surface)', borderRight: '1px solid var(--border)', padding: '24px 16px', display: 'flex', flexDirection: 'column', gap: 8, position: 'sticky', top: 0, height: '100vh' }}>
        <div style={{ fontFamily: 'Syne', fontWeight: 800, fontSize: '1.2rem', marginBottom: 16, padding: '0 8px' }}>⬡ SkillSphere</div>
        {[
          { icon: '🏠', label: 'Dashboard', path: '/dashboard' },
          { icon: '🔭', label: 'Explore', path: '/explore' },
          { icon: '👤', label: 'Profile', path: '/profile' },
        ].map(item => (
          <button key={item.label} className="btn btn-ghost" style={{ justifyContent: 'flex-start', gap: 10, padding: '10px 12px' }}
            onClick={() => navigate(item.path)}>{item.icon} {item.label}</button>
        ))}
        <button className="btn btn-ghost" style={{ justifyContent: 'flex-start', gap: 10, padding: '10px 12px', marginTop: 'auto', color: 'var(--muted)' }} onClick={handleLogout}>🚪 Logout</button>
      </div>

      {/* Main */}
      <div style={{ flex: 1, padding: '40px 32px', maxWidth: 900 }}>
        <div style={{ marginBottom: 32 }}>
          <h1 style={{ fontSize: '1.8rem', marginBottom: 4 }}>Welcome back, {user?.name?.split(' ')[0]}! 👋</h1>
          <p style={{ color: 'var(--muted)' }}>Keep up your streak and earn more XP today</p>
        </div>

        {/* Stats */}
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: 16, marginBottom: 32 }}>
          {[
            { label: 'Total XP', value: user?.xp || 0, icon: '⚡', color: 'var(--accent)' },
            { label: 'Level', value: user?.level || 1, icon: '🎯', color: 'var(--accent2)' },
            { label: 'Streak', value: `${user?.streak || 0} 🔥`, icon: '🔥', color: '#FBBF24' },
          ].map(stat => (
            <div key={stat.label} className="card" style={{ padding: 20, textAlign: 'center' }}>
              <div style={{ fontSize: '1.5rem', marginBottom: 8 }}>{stat.icon}</div>
              <div style={{ fontSize: '1.8rem', fontWeight: 800, color: stat.color, fontFamily: 'Syne' }}>{stat.value}</div>
              <div style={{ color: 'var(--muted)', fontSize: '0.8rem', marginTop: 4 }}>{stat.label}</div>
            </div>
          ))}
        </div>

        {/* Enrolled Skills */}
        <h2 style={{ fontSize: '1.2rem', marginBottom: 16 }}>My Skills</h2>
        {enrolled.length === 0 ? (
          <div className="card" style={{ padding: 40, textAlign: 'center' }}>
            <div style={{ fontSize: '3rem', marginBottom: 12 }}>🚀</div>
            <h3 style={{ marginBottom: 8 }}>Start your first skill!</h3>
            <p style={{ color: 'var(--muted)', marginBottom: 20 }}>Browse 120+ skills and start learning for free</p>
            <button className="btn btn-primary" onClick={() => navigate('/explore')}>Explore Skills →</button>
          </div>
        ) : (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 12, marginBottom: 32 }}>
            {enrolled.map(skill => {
              const totalL = skill.modules.reduce((a, m) => a + m.lessons.length, 0);
              const prog = getSkillProgress(skill.id, totalL);
              return (
                <div key={skill.id} className="card" style={{ padding: 20, display: 'flex', alignItems: 'center', gap: 16, cursor: 'pointer' }}
                  onClick={() => navigate(`/skill/${skill.slug}`)}>
                  <span style={{ fontSize: '2rem' }}>{skill.icon}</span>
                  <div style={{ flex: 1 }}>
                    <div style={{ fontWeight: 700, marginBottom: 6 }}>{skill.name}</div>
                    <div style={{ background: 'var(--surface2)', borderRadius: 4, height: 6, overflow: 'hidden' }}>
                      <div style={{ width: `${prog.percent}%`, height: '100%', background: skill.color, borderRadius: 4, transition: 'width 0.4s' }} />
                    </div>
                  </div>
                  <span style={{ color: skill.color, fontWeight: 700, fontSize: '0.9rem' }}>{prog.percent}%</span>
                </div>
              );
            })}
          </div>
        )}

        {/* Quick Explore */}
        <h2 style={{ fontSize: '1.2rem', marginBottom: 16 }}>Trending Skills</h2>
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(150px, 1fr))', gap: 12 }}>
          {SKILLS.slice(0, 4).map(skill => (
            <div key={skill.id} className="card" style={{ padding: 18, textAlign: 'center', cursor: 'pointer', borderColor: skill.color + '44' }}
              onClick={() => navigate(`/skill/${skill.slug}`)}>
              <div style={{ fontSize: '2rem', marginBottom: 8 }}>{skill.icon}</div>
              <div style={{ fontWeight: 700, fontSize: '0.85rem' }}>{skill.name}</div>
              <div style={{ color: skill.color, fontSize: '0.75rem', marginTop: 4 }}>{skill.category}</div>
            </div>
          ))}
        </div>
      </div>

      {/* AI Chat Button */}
      <button onClick={() => setShowChat(true)}
        style={{ position: 'fixed', bottom: 28, right: 28, width: 56, height: 56, borderRadius: '50%', background: 'linear-gradient(135deg, var(--accent), var(--accent2))', border: 'none', cursor: 'pointer', fontSize: '1.4rem', boxShadow: '0 4px 20px rgba(110,231,183,0.4)', zIndex: 100 }}>
        ⚡
      </button>
      {showChat && <AIChat onClose={() => setShowChat(false)} />}
    </div>
  );
}
